selector_to_html = {"a[href=\"render/motion_correction.html#create-the-parameters-we-pass-to-caiman\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Create the parameters we pass to CaImAn<a class=\"headerlink\" href=\"#create-the-parameters-we-pass-to-caiman\" title=\"Link to this heading\">#</a></h2><p>The above patch view looks good, so we use those values in our parameters dictionary.</p><p>You <em>can</em> also include segmentation parameters in this dictionary if you wish. This is <em>not recommmended</em> as several parameters share similar names yet perform different actions. i.e:</p>", "a[href=\"render/batch_helpers.html#remove-results-from-dataframe\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Remove results from dataframe<a class=\"headerlink\" href=\"#remove-results-from-dataframe\" title=\"Link to this heading\">#</a></h2>", "a[href=\"render/motion_correction.html#evaluate-motion-correction-outputs-with-mesmerize-core-api\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Evaluate motion correction outputs with <code class=\"docutils literal notranslate\"><span class=\"pre\">mesmerize-core</span></code> API<a class=\"headerlink\" href=\"#evaluate-motion-correction-outputs-with-mesmerize-core-api\" title=\"Link to this heading\">#</a></h2><p>mesmerize-core offers an easy <a class=\"reference external\" href=\"https://mesmerize-core.readthedocs.io/en/latest/api/mcorr.html\">API</a> to retrieve results from the batch dataframe.</p>", "a[href=\"render/segmentation.html#parameter-gridsearch\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Parameter Gridsearch<a class=\"headerlink\" href=\"#parameter-gridsearch\" title=\"Link to this heading\">#</a></h1><p>As shown for motion correction, the purpose of <code class=\"docutils literal notranslate\"><span class=\"pre\">mesmerize-core</span></code> is to perform parameter searches</p>", "a[href=\"render/collation.html#z-stack-alignment\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">z-stack alignment<a class=\"headerlink\" href=\"#z-stack-alignment\" title=\"Link to this heading\">#</a></h2>", "a[href=\"render/batch_helpers.html#rechunk-outputs-for-fast-frame-access-view-movies\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Rechunk outputs for fast frame access (view movies)<a class=\"headerlink\" href=\"#rechunk-outputs-for-fast-frame-access-view-movies\" title=\"Link to this heading\">#</a></h1>", "a[href=\"render/batch_helpers.html#manage-batch-and-dataframe-filepath-locations\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Manage batch and dataframe filepath locations<a class=\"headerlink\" href=\"#manage-batch-and-dataframe-filepath-locations\" title=\"Link to this heading\">#</a></h1><h2>Remove rows with no output (accidental entries)<a class=\"headerlink\" href=\"#remove-rows-with-no-output-accidental-entries\" title=\"Link to this heading\">#</a></h2>", "a[href=\"render/segmentation.html#reconstructed-movie-a-c\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Reconstructed movie - <code class=\"docutils literal notranslate\"><span class=\"pre\">A</span> <span class=\"pre\">*</span> <span class=\"pre\">C</span></code><a class=\"headerlink\" href=\"#reconstructed-movie-a-c\" title=\"Link to this heading\">#</a></h1>", "a[href=\"render/motion_correction.html#optional-view-hardware-information\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">(optional): View hardware information<a class=\"headerlink\" href=\"#optional-view-hardware-information\" title=\"Link to this heading\">#</a></h2>", "a[href=\"render/assembly.html#initialize-a-scanreader-object\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Initialize a scanreader object<a class=\"headerlink\" href=\"#initialize-a-scanreader-object\" title=\"Link to this heading\">#</a></h2><p>(Option 1). Simply pass a string containing a wildcard pattern for files to gather</p>", "a[href=\"render/segmentation.html#cnmf-object\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">CNMF Object<a class=\"headerlink\" href=\"#cnmf-object\" title=\"Link to this heading\">#</a></h2>", "a[href=\"render/motion_correction.html#load-a-data-file-to-examine\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Load a data file to examine<a class=\"headerlink\" href=\"#load-a-data-file-to-examine\" title=\"Link to this heading\">#</a></h2>", "a[href=\"render/segmentation.html#checking-for-an-errors\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Checking for an errors<a class=\"headerlink\" href=\"#checking-for-an-errors\" title=\"Link to this heading\">#</a></h2><p>After a batch run, check the results to make sure the outputs do not contain a \u201ctraceback\u201d error.</p><p>An error-free processing run will yield \u201cNone\u201d in the cell below. Otherwise, an error will be printed.</p>", "a[href=\"render/segmentation.html#cnmf-outputs\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">CNMF outputs<a class=\"headerlink\" href=\"#cnmf-outputs\" title=\"Link to this heading\">#</a></h1><p>Similar to mcorr, you can use the <code class=\"docutils literal notranslate\"><span class=\"pre\">mesmerize-core</span></code> API to fetch the outputs.</p><p><a class=\"reference external\" href=\"https://mesmerize-core.readthedocs.io/en/latest/api/cnmf.html\">API reference for mesmerize-CNMF</a>\n<a class=\"reference external\" href=\"https://caiman.readthedocs.io/en/latest/Getting_Started.html#parameters\">API reference for caiman-CNMF</a></p>", "a[href=\"render/segmentation.html#run-the-cnmf-batch-items\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Run the <code class=\"docutils literal notranslate\"><span class=\"pre\">cnmf</span></code> batch items<a class=\"headerlink\" href=\"#run-the-cnmf-batch-items\" title=\"Link to this heading\">#</a></h1>", "a[href=\"render/batch_helpers.html#remove-rows-with-no-output-accidental-entries\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Remove rows with no output (accidental entries)<a class=\"headerlink\" href=\"#remove-rows-with-no-output-accidental-entries\" title=\"Link to this heading\">#</a></h2>", "a[href=\"render/motion_correction.html#first-registration-run\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">First registration run<a class=\"headerlink\" href=\"#first-registration-run\" title=\"Link to this heading\">#</a></h2><p>If you ever get errors like</p>", "a[href=\"render/segmentation.html#residuals-y-ac-bf\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Residuals - <code class=\"docutils literal notranslate\"><span class=\"pre\">Y</span> <span class=\"pre\">-</span> <span class=\"pre\">AC</span> <span class=\"pre\">-</span> <span class=\"pre\">bf</span></code><a class=\"headerlink\" href=\"#residuals-y-ac-bf\" title=\"Link to this heading\">#</a></h1><p>Mesmerize-core provides these outputs as lazy arrays. This allows you to work with arrays that would otherwise be hundreds of gigabytes or terabytes in size.</p>", "a[href=\"render/segmentation.html#reconstructed-background-b-f\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Reconstructed background - <code class=\"docutils literal notranslate\"><span class=\"pre\">b</span> <span class=\"pre\">*</span> <span class=\"pre\">f</span></code><a class=\"headerlink\" href=\"#reconstructed-background-b-f\" title=\"Link to this heading\">#</a></h1>", "a[href=\"render/assembly.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Image Assembly<a class=\"headerlink\" href=\"#image-assembly\" title=\"Link to this heading\">#</a></h1><p>Raw ScanImage <code class=\"docutils literal notranslate\"><span class=\"pre\">.tiff</span></code> files are saved to disk in an interleaved manner. The general workflow is as follows:</p>", "a[href=\"render/motion_correction.html#apply-registration-using-the-same-parameters-to-the-remaining-files\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Apply registration using the same parameters to the remaining files<a class=\"headerlink\" href=\"#apply-registration-using-the-same-parameters-to-the-remaining-files\" title=\"Link to this heading\">#</a></h2>", "a[href=\"render/collation.html#get-outputs-for-each-z-plane\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Get outputs for each z-plane<a class=\"headerlink\" href=\"#get-outputs-for-each-z-plane\" title=\"Link to this heading\">#</a></h2>", "a[href=\"render/segmentation.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Segmentation<a class=\"headerlink\" href=\"#segmentation\" title=\"Link to this heading\">#</a></h1><p>Extract neuronal locations and planar time-traces.</p>", "a[href=\"render/segmentation.html#run-cnmf\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Run CNMF<a class=\"headerlink\" href=\"#run-cnmf\" title=\"Link to this heading\">#</a></h1><p>The API is identical to running mcorr.</p><p>You can provide the mcorr item row to <code class=\"docutils literal notranslate\"><span class=\"pre\">input_movie_path</span></code> and it will resolve the path of the input movie from the entry in the DataFrame.</p>", "a[href=\"render/motion_correction.html#quality-metrics-correlation-projections-pixel-shifts\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Quality metrics: correlation, projections, pixel shifts<a class=\"headerlink\" href=\"#quality-metrics-correlation-projections-pixel-shifts\" title=\"Link to this heading\">#</a></h2><p>Create a couple of summary images of the movie, including:</p>", "a[href=\"render/motion_correction.html#parameter-grid-search-if-you-need-it\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Parameter Grid Search (if you need it!)<a class=\"headerlink\" href=\"#parameter-grid-search-if-you-need-it\" title=\"Link to this heading\">#</a></h2><p>More runs with varying parameters, stored on disk in the dataframe batch.pickle</p>", "a[href=\"render/batch_helpers.html#add-a-comment\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Add a <code class=\"docutils literal notranslate\"><span class=\"pre\">comment</span></code><a class=\"headerlink\" href=\"#add-a-comment\" title=\"Link to this heading\">#</a></h2>", "a[href=\"render/segmentation.html#cnmf\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">CNMF<a class=\"headerlink\" href=\"#cnmf\" title=\"Link to this heading\">#</a></h2><p>Run the CaImAn <code class=\"docutils literal notranslate\"><span class=\"pre\">CNMF</span></code> algorithm using the mcorr output obtained in the last processing step.</p>", "a[href=\"render/collation.html#align-each-plane-to-the-reference-plane\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">1. Align each plane to the reference plane<a class=\"headerlink\" href=\"#align-each-plane-to-the-reference-plane\" title=\"Link to this heading\">#</a></h2>", "a[href=\"render/segmentation.html#load-outputs\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Load outputs<a class=\"headerlink\" href=\"#load-outputs\" title=\"Link to this heading\">#</a></h1>", "a[href=\"render/assembly.html#path-to-save-your-files\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Path to save your files<a class=\"headerlink\" href=\"#path-to-save-your-files\" title=\"Link to this heading\">#</a></h2><p>We can save the assembled image or individual ROIs to disk. The currently supported file extensions are <code class=\"docutils literal notranslate\"><span class=\"pre\">.tiff</span></code> and <code class=\"docutils literal notranslate\"><span class=\"pre\">.zarr</span></code>.</p>", "a[href=\"render/collation.html#total-number-of-neurons\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Total number of Neurons<a class=\"headerlink\" href=\"#total-number-of-neurons\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#tutorial\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Tutorial<a class=\"headerlink\" href=\"#tutorial\" title=\"Link to this heading\">#</a></h1><p>Below are <a class=\"reference external\" href=\"https://github.com/MillerBrainObservatory/LBM-CaImAn-Python/tree/master/demos/notebooks\">example notebooks</a> that walk users through the full processing pipeline.</p><p>To download these notebooks:</p>", "a[href=\"render/batch_helpers.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Batch Helpers<a class=\"headerlink\" href=\"#batch-helpers\" title=\"Link to this heading\">#</a></h1><p>Notebook cells to help:</p>", "a[href=\"render/motion_correction.html#view-metadata\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">View metadata<a class=\"headerlink\" href=\"#view-metadata\" title=\"Link to this heading\">#</a></h2><p><code class=\"docutils literal notranslate\"><span class=\"pre\">lcp.get_metadata(filepath)</span></code> works on raw scanimage files and files processed through <code class=\"docutils literal notranslate\"><span class=\"pre\">lcp.save_as()</span></code></p>", "a[href=\"render/segmentation.html#exploring-spatial-components-neuron-masks-and-temporal-components-traces\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Exploring spatial components (neuron masks) and temporal components (traces)<a class=\"headerlink\" href=\"#exploring-spatial-components-neuron-masks-and-temporal-components-traces\" title=\"Link to this heading\">#</a></h2><h3>Feed a list of indices to get back specific traces of interest<a class=\"headerlink\" href=\"#feed-a-list-of-indices-to-get-back-specific-traces-of-interest\" title=\"Link to this heading\">#</a></h3>", "a[href=\"render/motion_correction.html#registration-parameters\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Registration parameters<a class=\"headerlink\" href=\"#registration-parameters\" title=\"Link to this heading\">#</a></h2><p>Here\u2019s a markdown table describing the parameters:</p>", "a[href=\"render/segmentation.html#interactive-parameter-exploration\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Interactive Parameter Exploration<a class=\"headerlink\" href=\"#interactive-parameter-exploration\" title=\"Link to this heading\">#</a></h1><h2>Exploring spatial components (neuron masks) and temporal components (traces)<a class=\"headerlink\" href=\"#exploring-spatial-components-neuron-masks-and-temporal-components-traces\" title=\"Link to this heading\">#</a></h2><h3>Feed a list of indices to get back specific traces of interest<a class=\"headerlink\" href=\"#feed-a-list-of-indices-to-get-back-specific-traces-of-interest\" title=\"Link to this heading\">#</a></h3>", "a[href=\"render/assembly.html#input-data-path-to-your-raw-tiff-file-s\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Input data: Path to your raw .tiff file(s)<a class=\"headerlink\" href=\"#input-data-path-to-your-raw-tiff-file-s\" title=\"Link to this heading\">#</a></h2><p>Before processing, ensure:</p>", "a[href=\"render/collation.html#id1\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">2. Align each plane to the reference plane<a class=\"headerlink\" href=\"#id1\" title=\"Link to this heading\">#</a></h2>", "a[href=\"render/motion_correction.html#preview-data-with-scalebars\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Preview data with scalebars<a class=\"headerlink\" href=\"#preview-data-with-scalebars\" title=\"Link to this heading\">#</a></h2><p><code class=\"docutils literal notranslate\"><span class=\"pre\">plot_data_with_scalebars</span></code> will give you 3 images, at 5, 10 and 20 um. Take note of the approximate size of the neurons in your data.</p><p>You can use a single frame:</p>", "a[href=\"render/collation.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Collate Planes<a class=\"headerlink\" href=\"#collate-planes\" title=\"Link to this heading\">#</a></h1><p>In this notebook, we merge CNMF results across each of our z-planes.</p>", "a[href=\"render/motion_correction.html#visualize-patches\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Visualize patches<a class=\"headerlink\" href=\"#visualize-patches\" title=\"Link to this heading\">#</a></h2><p>The <code class=\"docutils literal notranslate\"><span class=\"pre\">generate_patch_view</span></code> function divides the image into patches the same way CaImAn does internally.</p><p>Increasing / decreasing the <code class=\"docutils literal notranslate\"><span class=\"pre\">target_patch_size</span></code> and <code class=\"docutils literal notranslate\"><span class=\"pre\">overlap_fraction</span></code> parameters to examine the effect of different stride/overlap values displayed in the title.</p>", "a[href=\"render/segmentation.html#using-lazyarrays\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Using LazyArrays<a class=\"headerlink\" href=\"#using-lazyarrays\" title=\"Link to this heading\">#</a></h1>", "a[href=\"render/collation.html#combine-results-of-different-z-planes\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Combine results of different z_planes<a class=\"headerlink\" href=\"#combine-results-of-different-z-planes\" title=\"Link to this heading\">#</a></h2>", "a[href=\"#contents\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Contents<a class=\"headerlink\" href=\"#contents\" title=\"Link to this heading\">#</a></h2>", "a[href=\"render/batch_helpers.html#convert-intermediate-mmmap-to-zarr\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Convert intermediate <code class=\"docutils literal notranslate\"><span class=\"pre\">.mmmap</span></code> to <code class=\"docutils literal notranslate\"><span class=\"pre\">.zarr</span></code><a class=\"headerlink\" href=\"#convert-intermediate-mmmap-to-zarr\" title=\"Link to this heading\">#</a></h1>", "a[href=\"render/motion_correction.html#data-path-setup\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Data path setup<a class=\"headerlink\" href=\"#data-path-setup\" title=\"Link to this heading\">#</a></h2><p>We set 2 path variables:</p>", "a[href=\"render/motion_correction.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Registration<a class=\"headerlink\" href=\"#registration\" title=\"Link to this heading\">#</a></h1><p>Correct for rigid/non-rigid movement</p>", "a[href=\"render/assembly.html#preview-the-scanreader-object\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Preview the scanreader object<a class=\"headerlink\" href=\"#preview-the-scanreader-object\" title=\"Link to this heading\">#</a></h2><p>The scanreader object contains the following attributes:</p>", "a[href=\"render/batch_helpers.html#change-correct-input-movie-path\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Change/correct <code class=\"docutils literal notranslate\"><span class=\"pre\">input_movie_path</span></code><a class=\"headerlink\" href=\"#change-correct-input-movie-path\" title=\"Link to this heading\">#</a></h2>", "a[href=\"render/batch_helpers.html#change-the-item-name\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Change the <code class=\"docutils literal notranslate\"><span class=\"pre\">item_name</span></code><a class=\"headerlink\" href=\"#change-the-item-name\" title=\"Link to this heading\">#</a></h2>", "a[href=\"render/segmentation.html#caiman-docs-on-component-eval\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Caiman docs on component eval<a class=\"headerlink\" href=\"#caiman-docs-on-component-eval\" title=\"Link to this heading\">#</a></h2><p>https://caiman.readthedocs.io/en/latest/Getting_Started.html#component-evaluation</p><p>The quality of detected components is evaluated with three parameters:</p>", "a[href=\"render/segmentation.html#pull-contours-good-components\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Pull contours / good components<a class=\"headerlink\" href=\"#pull-contours-good-components\" title=\"Link to this heading\">#</a></h2><p>View the diffs</p>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
